$ErrorActionPreference = 'Stop'; $files = Get-ChildItem -LiteralPath 'public/locales' -Recurse -Filter '*.json' -File; $bad = @(); foreach ($f in $files) { try { [System.Text.Json.JsonDocument]::Parse((Get-Content -Raw -LiteralPath $f.FullName)) | Out-Null } catch { $bad += [pscustomobject]@{ file = $f.FullName; error = $_.Exception.Message } } }; if ($bad.Count -eq 0) { 'OK: all JSON valid' } else { $bad | Format-Table -AutoSize; exit 1 }